import pytest
import requests

def test_access_denied_at_exactly_15_minute_sla_boundary(
    data_consumer_auth_fixture, fhir_base_url,
    existing_revoked_consent, patient_id, time_travel_fixture
):
    SLA_SECONDS = 900  # 15 minutes

    time_travel_fixture.set_offset(SLA_SECONDS)

    c_headers = {"Authorization": f"Bearer {data_consumer_auth_fixture}"}
    at_boundary = requests.get(
        f"{fhir_base_url}/Patient/{patient_id}/$everything", headers=c_headers
    )
    assert at_boundary.status_code in (401, 403), (
        f"Access must be denied at T+900s, got {at_boundary.status_code}"
    )

    time_travel_fixture.set_offset(SLA_SECONDS + 1)
    past_boundary = requests.get(
        f"{fhir_base_url}/Patient/{patient_id}/$everything", headers=c_headers
    )
    assert past_boundary.status_code in (200, 401, 403), (
        f"Unexpected status past SLA boundary: {past_boundary.status_code}"
    )

    time_travel_fixture.reset()

import pytest
import requests

@pytest.mark.parametrize("missing_field,incomplete_payload", [
    ("status", {"resourceType": "Consent", "scope": {"coding": [{"code": "patient-privacy"}]}, "category": [{"coding": [{"code": "59284-0"}]}]}),
    ("scope", {"resourceType": "Consent", "status": "active", "category": [{"coding": [{"code": "59284-0"}]}]}),
    ("category", {"resourceType": "Consent", "status": "active", "scope": {"coding": [{"code": "patient-privacy"}]}}),
])
def test_consent_missing_mandatory_elements_returns_422(
    patient_auth_fixture, fhir_base_url, missing_field, incomplete_payload
):
    token = patient_auth_fixture
    headers = {"Authorization": f"Bearer {token}", "Content-Type": "application/fhir+json"}

    post_resp = requests.post(f"{fhir_base_url}/Consent", json=incomplete_payload, headers=headers)
    assert post_resp.status_code == 422, (
        f"Expected 422 for missing '{missing_field}', got {post_resp.status_code}"
    )
    body = post_resp.json()
    assert body.get("resourceType") == "OperationOutcome", "Expected OperationOutcome for validation failure"
    issues = body.get("issue", [])
    assert len(issues) > 0, "OperationOutcome must contain at least one issue"
